+    func buildSpacesByDisplay(
+        managedSpaces: NSArray,
+        activeSpace: CGSSpaceID
+    ) -> [CGDirectDisplayID: [SpaceInfo]] {
+        var spacesByDisplay: [CGDirectDisplayID: [SpaceInfo]] = [:]
+
+        for case let displayDict as [String: Any] in managedSpaces {
